def hill_climbing(problem, max_iterations=1000):
    """
    Hill Climbing - Steepest Ascent Variant
    problem: object with initial_state(), goal_test(), 
             successors(), and heuristic() methods
    """
    current = problem.initial_state()

    for _ in range(max_iterations):
        neighbors = problem.successors(current)

        if not neighbors:
            break

        # Find best neighbor
        best_neighbor = max(neighbors, key=problem.heuristic)

        # If no improvement, we reached local maximum
        if problem.heuristic(best_neighbor) <= problem.heuristic(current):
            return current, problem.heuristic(current)

        current = best_neighbor

        if problem.goal_test(current):
            return current, problem.heuristic(current)

    return current, problem.heuristic(current)

def random_restart_hill_climbing(problem, restarts=10):
    """Run hill climbing multiple times from random initial states"""
    best_state = None
    best_value = float('-inf')

    for _ in range(restarts):
        problem.reset_to_random_state()
        state, value = hill_climbing(problem)

        if value > best_value:
            best_value = value
            best_state = state

        if problem.goal_test(state):
            break

    return best_state, best_value

# Example: Simple numerical optimization
class NumericalProblem:
    def __init__(self):
        self.state = 0

    def initial_state(self):
        import random
        self.state = random.uniform(-10, 10)
        return self.state

    def successors(self, x):
        return [x + 0.1, x - 0.1]  # Small steps

    def heuristic(self, x):
        return -x**2 + 10  # Maximize: peaks at x=0

    def goal_test(self, x):
        return abs(x) < 0.01

problem = NumericalProblem()
solution, value = hill_climbing(problem)
print(f"Solution: x={solution:.4f}, f(x)={value:.4f}")
